document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll('[data-bs-toggle="tooltip"]:not(#add-btn)').forEach(t=>{const e=t.getAttribute("data-tooltip-max-width"),d=bootstrap.Tooltip.getOrCreateInstance(t);t.addEventListener("inserted.bs.tooltip",()=>{const d=t.getAttribute("aria-describedby"),o=d&&document.getElementById(d);o&&e&&o.style.setProperty("--bs-tooltip-max-width",e)}),t.addEventListener("click",()=>d.hide()),t.addEventListener("blur",()=>d.hide())});const t=document.getElementById("add-btn");if(t){const e=t.getAttribute("data-tooltip-max-width"),d=t.getAttribute("title");if(d){const o=bootstrap.Tooltip.getOrCreateInstance(t,{title:d,placement:"bottom"});t.addEventListener("inserted.bs.tooltip",()=>{const d=t.getAttribute("aria-describedby"),o=d&&document.getElementById(d);o&&e&&o.style.setProperty("--bs-tooltip-max-width",e)}),t.addEventListener("click",()=>o.hide()),t.addEventListener("blur",()=>o.hide())}}});